import{_ as e,o as n,c as r,a as o}from"./chunks/framework.8tiMeCK-.js";const h=JSON.parse('{"title":"14.14  方法速查表（工具箱里的扳手和螺丝刀）","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch14_14.md","filePath":"notes/linux_kernel_networking/ch14_14.md","lastUpdated":null}'),s={name:"notes/linux_kernel_networking/ch14_14.md"};function i(c,t,a,d,u,l){return n(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="_14-14-方法速查表-工具箱里的扳手和螺丝刀" tabindex="-1">14.14 方法速查表（工具箱里的扳手和螺丝刀） <a class="header-anchor" href="#_14-14-方法速查表-工具箱里的扳手和螺丝刀" aria-label="Permalink to &quot;14.14  方法速查表（工具箱里的扳手和螺丝刀）&quot;">​</a></h1><p>前面的旅程就真的到头了。</p><p>回想一下，这一章我们跨了很大的步子：</p><ul><li>我们从 <strong>Namespace</strong> 开始，建立了隔离的视角。</li><li>用 <strong>Cgroup</strong> 给资源套上了缰绳。</li><li>跑到 <strong>蓝牙</strong>、<strong>802.15.4</strong> 和 <strong>NFC</strong> 的无线世界里看了看那些奇怪的协议。</li><li>还钻进了内核的 <strong>通知链</strong> 和 <strong>PCI</strong> 子系统。</li><li>最后，我们看了一眼 <strong>PPPoE</strong> 和 <strong>Android</strong> 这种把底层技术包装成上层平台的复杂案例。</li></ul><p>还记得这一章开头我们说的吗？Linux 网络子系统是一个巨大的机器。这一章里的每一个小节——无论是多核的 RPS，还是 Android 的 HAL——其实都是在回答一个问题：<strong>当这个机器变得更复杂、更多核、更移动化时，我们要怎么驾驭它？</strong></p><p>现在书已经翻到了最后一页。Linux 网络是一个浩瀚的海洋，新的特性还在不断地涌入内核主线。希望这本书不仅能让你学到几个 API 或几段代码，更能给你一张地图，让你在以后面对 <code>ethtool</code> 的输出或者内核崩溃日志时，知道该往哪里看，该问什么问题。</p><p>调试愉快！</p><hr><p>为了方便你在后续的代码探险中查阅，我把这一章我们亲手摸过的那些核心内核方法和 API 整理成了这份速查表。你可以把它看作是<strong>工具箱里的说明书</strong>——不是为了从头读，而是为了在你写着写着突然想不起来「那个递增引用计数的函数叫什么来着？」的时候，能在这里立刻找到那把正确的扳手。</p><h3 id="namespace-管理" tabindex="-1">Namespace 管理 <a class="header-anchor" href="#namespace-管理" aria-label="Permalink to &quot;Namespace 管理&quot;">​</a></h3><p>Namespace 是我们隔离世界的透镜。这一组方法负责创建、切换和销毁这些透镜。</p><h4 id="void-switch-task-namespaces-struct-task-struct-p-struct-nsproxy-new" tabindex="-1"><code>void switch_task_namespaces(struct task_struct *p, struct nsproxy *new);</code> <a class="header-anchor" href="#void-switch-task-namespaces-struct-task-struct-p-struct-nsproxy-new" aria-label="Permalink to &quot;`void switch_task_namespaces(struct task_struct *p, struct nsproxy *new);`&quot;">​</a></h4><p><strong>做什么</strong>：给指定的进程（<code>p</code>）换上一套新的「眼镜」（<code>nsproxy</code>）。 <strong>实质</strong>：这行代码执行后，该进程就彻底进入了新的命名空间视图——它看到的网络设备、主机名、PID 都会变成新 <code>nsproxy</code> 指向的那些。</p><h4 id="struct-nsproxy-create-nsproxy-void" tabindex="-1"><code>struct nsproxy *create_nsproxy(void);</code> <a class="header-anchor" href="#struct-nsproxy-create-nsproxy-void" aria-label="Permalink to &quot;`struct nsproxy *create_nsproxy(void);`&quot;">​</a></h4><p><strong>做什么</strong>：分配一个新的 <code>nsproxy</code> 结构体。 <strong>细节</strong>：不仅分配内存，还会把它的引用计数初始化为 1。这是创建新命名空间视图的第一步。</p><h4 id="void-free-nsproxy-struct-nsproxy-ns" tabindex="-1"><code>void free_nsproxy(struct nsproxy *ns);</code> <a class="header-anchor" href="#void-free-nsproxy-struct-nsproxy-ns" aria-label="Permalink to &quot;`void free_nsproxy(struct nsproxy *ns);`&quot;">​</a></h4><p><strong>做什么</strong>：释放指定的 <code>nsproxy</code> 对象占用的资源。 <strong>注意</strong>：通常在引用计数归零时调用。</p><h4 id="struct-nsproxy-task-nsproxy-struct-task-struct-tsk" tabindex="-1"><code>struct nsproxy *task_nsproxy(struct task_struct *tsk);</code> <a class="header-anchor" href="#struct-nsproxy-task-nsproxy-struct-task-struct-tsk" aria-label="Permalink to &quot;`struct nsproxy *task_nsproxy(struct task_struct *tsk);`&quot;">​</a></h4><p><strong>做什么</strong>：获取指定进程当前佩戴的「眼镜」。 <strong>用途</strong>：当你有一个进程的 <code>task_struct</code> 却不知道它属于哪个命名空间时，用这个函数。</p><h4 id="void-get-nsproxy-struct-nsproxy-ns" tabindex="-1"><code>void get_nsproxy(struct nsproxy *ns);</code> <a class="header-anchor" href="#void-get-nsproxy-struct-nsproxy-ns" aria-label="Permalink to &quot;`void get_nsproxy(struct nsproxy *ns);`&quot;">​</a></h4><p><strong>做什么</strong>：给 <code>nsproxy</code> 的引用计数加 1。 <strong>目的</strong>：防止在你使用它的时候被别人释放掉。</p><h4 id="void-put-nsproxy-struct-nsproxy-ns" tabindex="-1"><code>void put_nsproxy(struct nsproxy *ns);</code> <a class="header-anchor" href="#void-put-nsproxy-struct-nsproxy-ns" aria-label="Permalink to &quot;`void put_nsproxy(struct nsproxy *ns);`&quot;">​</a></h4><p><strong>做什么</strong>：给 <code>nsproxy</code> 的引用计数减 1。 <strong>触发</strong>：如果减到 0，内核会调用 <code>free_nsproxy()</code> 彻底清理它。</p><hr><h3 id="网络命名空间" tabindex="-1">网络命名空间 <a class="header-anchor" href="#网络命名空间" aria-label="Permalink to &quot;网络命名空间&quot;">​</a></h3><p>这是网络子系统里最核心的隔离机制。下面的每一个函数都在操作 <code>struct net</code> —— 那个代表了整个网络协议栈视图的对象。</p><h4 id="struct-net-dev-net-const-struct-net-device-dev" tabindex="-1"><code>struct net *dev_net(const struct net_device *dev);</code> <a class="header-anchor" href="#struct-net-dev-net-const-struct-net-device-dev" aria-label="Permalink to &quot;`struct net *dev_net(const struct net_device *dev);`&quot;">​</a></h4><p><strong>做什么</strong>：回答「这个网卡属于哪个网络空间？」。 <strong>返回</strong>：<code>net_device</code> 里 <code>nd_net</code> 成员的值。</p><h4 id="void-dev-net-set-struct-net-device-dev-struct-net-net" tabindex="-1"><code>void dev_net_set(struct net_device *dev, struct net *net);</code> <a class="header-anchor" href="#void-dev-net-set-struct-net-device-dev-struct-net-net" aria-label="Permalink to &quot;`void dev_net_set(struct net_device *dev, struct net *net);`&quot;">​</a></h4><p><strong>做什么</strong>：把指定的网卡移动到指定的网络空间里。 <strong>实质</strong>：修改 <code>dev-&gt;nd_net</code> 指针。</p><h4 id="struct-net-sock-net-const-struct-sock-sk" tabindex="-1"><code>struct net *sock_net(const struct sock *sk);</code> <a class="header-anchor" href="#struct-net-sock-net-const-struct-sock-sk" aria-label="Permalink to &quot;`struct net *sock_net(const struct sock *sk);`&quot;">​</a></h4><p><strong>做什么</strong>：回答「这个 Socket 属于哪个网络空间？」。 <strong>返回</strong>：<code>sock</code> 结构里 <code>sk_net</code> 的值。</p><h4 id="void-sock-net-set-struct-sock-sk-struct-net-net" tabindex="-1"><code>void sock_net_set(struct sock *sk, struct net *net);</code> <a class="header-anchor" href="#void-sock-net-set-struct-sock-sk-struct-net-net" aria-label="Permalink to &quot;`void sock_net_set(struct sock *sk, struct net *net);`&quot;">​</a></h4><p><strong>做什么</strong>：给 Socket 指定一个归属的网络空间。 <strong>场景</strong>：Socket 创建时，必须把它挂到某个网络命名空间下，否则内核不知道该用哪张路由表。</p><h4 id="int-net-eq-const-struct-net-net1-const-struct-net-net2" tabindex="-1"><code>int net_eq(const struct net *net1, const struct net *net2);</code> <a class="header-anchor" href="#int-net-eq-const-struct-net-net1-const-struct-net-net2" aria-label="Permalink to &quot;`int net_eq(const struct net *net1, const struct net *net2);`&quot;">​</a></h4><p><strong>做什么</strong>：判断两个网络空间指针是不是同一个。 <strong>为什么需要它</strong>：因为有时候网络空间指针可能是 <code>&amp;init_net</code>，快速判断是否相等能避免不必要的查找。</p><h4 id="struct-net-net-alloc-void" tabindex="-1"><code>struct net *net_alloc(void);</code> <a class="header-anchor" href="#struct-net-net-alloc-void" aria-label="Permalink to &quot;`struct net *net_alloc(void);`&quot;">​</a></h4><p><strong>做什么</strong>：分配一个新的 <code>struct net</code> 对象。 <strong>位置</strong>：它是 <code>copy_net_ns()</code> 的内部实现细节。</p><h4 id="struct-net-copy-net-ns-unsigned-long-flags-struct-user-namespace-user-ns-struct-net-old-net" tabindex="-1"><code>struct net *copy_net_ns(unsigned long flags, struct user_namespace *user_ns, struct net *old_net);</code> <a class="header-anchor" href="#struct-net-copy-net-ns-unsigned-long-flags-struct-user-namespace-user-ns-struct-net-old-net" aria-label="Permalink to &quot;`struct net *copy_net_ns(unsigned long flags, struct user_namespace *user_ns, struct net *old_net);`&quot;">​</a></h4><p><strong>做什么</strong>：这是创建新网络空间的「总开关」。 <strong>逻辑</strong>：</p><ol><li>检查 <code>flags</code> 里有没有 <code>CLONE_NEWNET</code>。</li><li>如果有，调用 <code>net_alloc()</code> 分配新对象，再用 <code>setup_net()</code> 初始化，最后挂到全局链表 <code>net_namespace_list</code> 上。</li><li>如果没有，返回 <code>old_net</code>（大家共享一个）。 <strong>注意</strong>：如果内核没开 <code>CONFIG_NET_NS</code>，这个函数会变成一个空壳，只检查 <code>flags</code> 并直接返回旧空间。</li></ol><h4 id="int-setup-net-struct-net-net-struct-user-namespace-user-ns" tabindex="-1"><code>int setup_net(struct net *net, struct user_namespace *user_ns);</code> <a class="header-anchor" href="#int-setup-net-struct-net-net-struct-user-namespace-user-ns" aria-label="Permalink to &quot;`int setup_net(struct net *net, struct user_namespace *user_ns);`&quot;">​</a></h4><p><strong>做什么</strong>：初始化新分配的网络空间对象。 <strong>细节</strong>：设置 <code>user_ns</code>，把引用计数置为 1，并执行所有注册到 <code>pernet_operations</code> 的初始化回调。</p><h4 id="struct-net-get-net-ns-by-pid-pid-t-pid" tabindex="-1"><code>struct net *get_net_ns_by_pid(pid_t pid);</code> <a class="header-anchor" href="#struct-net-get-net-ns-by-pid-pid-t-pid" aria-label="Permalink to &quot;`struct net *get_net_ns_by_pid(pid_t pid);`&quot;">​</a></h4><p><strong>做什么</strong>：通过进程 PID 找到它所在的网络空间。 <strong>用途</strong>：当你只想操作「某个进程所在的网络空间」时，这步查找是必须的。</p><h4 id="struct-net-get-net-ns-by-fd-int-fd" tabindex="-1"><code>struct net *get_net_ns_by_fd(int fd);</code> <a class="header-anchor" href="#struct-net-get-net-ns-by-fd-int-fd" aria-label="Permalink to &quot;`struct net *get_net_ns_by_fd(int fd);`&quot;">​</a></h4><p><strong>做什么</strong>：通过文件描述符找到对应的网络空间。 <strong>原理</strong>：文件描述符可能指向一个代表网络空间的特殊文件（比如 <code>/proc/[pid]/ns/net</code> 的打开文件描述）。</p><h4 id="void-put-net-struct-net-net" tabindex="-1"><code>void put_net(struct net *net);</code> <a class="header-anchor" href="#void-put-net-struct-net-net" aria-label="Permalink to &quot;`void put_net(struct net *net);`&quot;">​</a></h4><p><strong>做什么</strong>：减少网络空间的引用计数。 <strong>后果</strong>：如果计数归零，调用 <code>__put_net()</code> 回收资源。</p><h4 id="struct-net-get-net-struct-net-net" tabindex="-1"><code>struct net *get_net(struct net *net);</code> <a class="header-anchor" href="#struct-net-get-net-struct-net-net" aria-label="Permalink to &quot;`struct net *get_net(struct net *net);`&quot;">​</a></h4><p><strong>做什么</strong>：增加网络空间的引用计数，并返回指针。 <strong>模式</strong>：典型的「获取并使用」模式，防止对象在使用中消失。</p><h4 id="int-dev-change-net-namespace-struct-net-device-dev-struct-net-net-const-char-pat" tabindex="-1"><code>int dev_change_net_namespace(struct net_device *dev, struct net *net, const char *pat);</code> <a class="header-anchor" href="#int-dev-change-net-namespace-struct-net-device-dev-struct-net-net-const-char-pat" aria-label="Permalink to &quot;`int dev_change_net_namespace(struct net_device *dev, struct net *net, const char *pat);`&quot;">​</a></h4><p><strong>做什么</strong>：把一个正在运行的网卡<strong>物理移动</strong>到另一个网络空间。 <strong>条件</strong>：调用者必须持有 <code>rtnl</code> 信号量（这是网络配置操作的锁）。 <strong>坑</strong>：如果网卡特性里设置了 <code>NETIF_F_NETNS_LOCAL</code>（意思是「我是本地设备，不能移动」），这个函数会直接返回 <code>-EINVAL</code>。有些虚拟设备是不允许跨命名空间迁移的。</p><hr><h3 id="网络命名空间子系统注册" tabindex="-1">网络命名空间子系统注册 <a class="header-anchor" href="#网络命名空间子系统注册" aria-label="Permalink to &quot;网络命名空间子系统注册&quot;">​</a></h3><p>当你写一个新的内核模块，并且想在每个网络空间创建时都做点什么事（比如初始化点数据结构），你需要用到这些注册函数。</p><h4 id="int-register-pernet-device-struct-pernet-operations-ops" tabindex="-1"><code>int register_pernet_device(struct pernet_operations *ops);</code> <a class="header-anchor" href="#int-register-pernet-device-struct-pernet-operations-ops" aria-label="Permalink to &quot;`int register_pernet_device(struct pernet_operations *ops);`&quot;">​</a></h4><p><strong>做什么</strong>：注册一个<strong>设备级</strong>的网络空间回调。 <strong>特点</strong>：顺序靠后，用于那些依赖其他基础设备已经初始化好的模块。</p><h4 id="void-unregister-pernet-device-struct-pernet-operations-ops" tabindex="-1"><code>void unregister_pernet_device(struct pernet_operations *ops);</code> <a class="header-anchor" href="#void-unregister-pernet-device-struct-pernet-operations-ops" aria-label="Permalink to &quot;`void unregister_pernet_device(struct pernet_operations *ops);`&quot;">​</a></h4><p><strong>做什么</strong>：注销上述回调。</p><h4 id="int-register-pernet-subsys-struct-pernet-operations-ops" tabindex="-1"><code>int register_pernet_subsys(struct pernet_operations *ops);</code> <a class="header-anchor" href="#int-register-pernet-subsys-struct-pernet-operations-ops" aria-label="Permalink to &quot;`int register_pernet_subsys(struct pernet_operations *ops);`&quot;">​</a></h4><p><strong>做什么</strong>：注册一个<strong>子系统级</strong>的网络空间回调。 <strong>特点</strong>：顺序靠前，用于核心子系统（比如路由表、协议栈）。</p><h4 id="void-unregister-pernet-subsys-struct-pernet-operations-ops" tabindex="-1"><code>void unregister_pernet_subsys(struct pernet_operations *ops);</code> <a class="header-anchor" href="#void-unregister-pernet-subsys-struct-pernet-operations-ops" aria-label="Permalink to &quot;`void unregister_pernet_subsys(struct pernet_operations *ops);`&quot;">​</a></h4><p><strong>做什么</strong>：注销上述回调。</p><hr><h3 id="uts-命名空间" tabindex="-1">UTS 命名空间 <a class="header-anchor" href="#uts-命名空间" aria-label="Permalink to &quot;UTS 命名空间&quot;">​</a></h3><p>UTS 空间里装的是主机名和域名。这是最简单的命名空间之一。</p><h4 id="struct-new-utsname-utsname-void" tabindex="-1"><code>struct new_utsname *utsname(void);</code> <a class="header-anchor" href="#struct-new-utsname-utsname-void" aria-label="Permalink to &quot;`struct new_utsname *utsname(void);`&quot;">​</a></h4><p><strong>做什么</strong>：获取当前进程的 UTS 名称结构。 <strong>快捷方式</strong>：相当于拿 <code>current-&gt;nsproxy-&gt;uts_ns-&gt;name</code>。</p><h4 id="struct-uts-namespace-clone-uts-ns-struct-user-namespace-user-ns-struct-uts-namespace-old-ns" tabindex="-1"><code>struct uts_namespace *clone_uts_ns(struct user_namespace *user_ns, struct uts_namespace *old_ns);</code> <a class="header-anchor" href="#struct-uts-namespace-clone-uts-ns-struct-user-namespace-user-ns-struct-uts-namespace-old-ns" aria-label="Permalink to &quot;`struct uts_namespace *clone_uts_ns(struct user_namespace *user_ns, struct uts_namespace *old_ns);`&quot;">​</a></h4><p><strong>做什么</strong>：克隆一个 UTS 空间。 <strong>逻辑</strong>：调用 <code>create_uts_ns()</code> 分配，然后把旧空间里的主机名拷贝过去。</p><h4 id="struct-uts-namespace-copy-utsname-unsigned-long-flags-struct-user-namespace-user-ns-struct-uts-namespace-old-ns" tabindex="-1"><code>struct uts_namespace *copy_utsname(unsigned long flags, struct user_namespace *user_ns, struct uts_namespace *old_ns);</code> <a class="header-anchor" href="#struct-uts-namespace-copy-utsname-unsigned-long-flags-struct-user-namespace-user-ns-struct-uts-namespace-old-ns" aria-label="Permalink to &quot;`struct uts_namespace *copy_utsname(unsigned long flags, struct user_namespace *user_ns, struct uts_namespace *old_ns);`&quot;">​</a></h4><p><strong>做什么</strong>：处理 <code>clone</code> 系统调用时的 UTS 空间创建。 <strong>逻辑</strong>：如果 <code>flags</code> 有 <code>CLONE_NEWUTS</code>，就调用 <code>clone_uts_ns()</code> 创建新的；否则返回旧的 <code>old_ns</code>。</p><hr><h3 id="proc-文件系统与-inode" tabindex="-1">Proc 文件系统与 Inode <a class="header-anchor" href="#proc-文件系统与-inode" aria-label="Permalink to &quot;Proc 文件系统与 Inode&quot;">​</a></h3><p>每个命名空间在 <code>/proc</code> 下都有一个唯一的身份证号。</p><h4 id="int-proc-alloc-inum-unsigned-int-inum" tabindex="-1"><code>int proc_alloc_inum(unsigned int *inum);</code> <a class="header-anchor" href="#int-proc-alloc-inum-unsigned-int-inum" aria-label="Permalink to &quot;`int proc_alloc_inum(unsigned int *inum);`&quot;">​</a></h4><p><strong>做什么</strong>：分配一个 proc inode 号码。 <strong>范围</strong>：在 <code>0xf0000000</code> 到 <code>0xffffffff</code> 之间。 <strong>用途</strong>：用来标识一个命名空间实例，确保在 <code>/proc</code> 里是唯一的。</p><h4 id="struct-pid-namespace-ns-of-pid-struct-pid-pid" tabindex="-1"><code>struct pid_namespace *ns_of_pid(struct pid *pid);</code> <a class="header-anchor" href="#struct-pid-namespace-ns-of-pid-struct-pid-pid" aria-label="Permalink to &quot;`struct pid_namespace *ns_of_pid(struct pid *pid);`&quot;">​</a></h4><p><strong>做什么</strong>：返回指定 PID 所属的 PID 命名空间。 <strong>用途</strong>：搞清楚一个 PID 是在哪个「盒子」里生成的。</p><hr><h3 id="cgroup-辅助" tabindex="-1">Cgroup 辅助 <a class="header-anchor" href="#cgroup-辅助" aria-label="Permalink to &quot;Cgroup 辅助&quot;">​</a></h3><p>Cgroup 是资源限制的笼子。这里是当进程释放时的一些处理。</p><h4 id="void-cgroup-release-agent-struct-work-struct-work" tabindex="-1"><code>void cgroup_release_agent(struct work_struct *work);</code> <a class="header-anchor" href="#void-cgroup-release-agent-struct-work-struct-work" aria-label="Permalink to &quot;`void cgroup_release_agent(struct work_struct *work);`&quot;">​</a></h4><p><strong>做什么</strong>：当一个 Cgroup 被释放时，调用这个函数。 <strong>实质</strong>：它会在用户空间启动一个辅助进程（通过 <code>call_usermodehelper()</code>），用来处理清理工作。</p><h4 id="int-call-usermodehelper-char-path-char-argv-char-envp-int-wait" tabindex="-1"><code>int call_usermodehelper(char * path, char ** argv, char ** envp, int wait);</code> <a class="header-anchor" href="#int-call-usermodehelper-char-path-char-argv-char-envp-int-wait" aria-label="Permalink to &quot;`int call_usermodehelper(char * path, char ** argv, char ** envp, int wait);`&quot;">​</a></h4><p><strong>做什么</strong>：从内核空间启动一个用户空间程序。 <strong>能力</strong>：内核能让你跑个脚本，靠的就是这个。</p><hr><h3 id="蓝牙协议栈" tabindex="-1">蓝牙协议栈 <a class="header-anchor" href="#蓝牙协议栈" aria-label="Permalink to &quot;蓝牙协议栈&quot;">​</a></h3><p>蓝牙那一套复杂的层级，靠这些方法粘在一起。</p><h4 id="int-bacmp-bdaddr-t-ba1-bdaddr-t-ba2" tabindex="-1"><code>int bacmp(bdaddr_t *ba1, bdaddr_t *ba2);</code> <a class="header-anchor" href="#int-bacmp-bdaddr-t-ba1-bdaddr-t-ba2" aria-label="Permalink to &quot;`int bacmp(bdaddr_t *ba1, bdaddr_t *ba2);`&quot;">​</a></h4><p><strong>做什么</strong>：比较两个蓝牙地址。 <strong>返回</strong>：0 表示相等。</p><h4 id="void-bacpy-bdaddr-t-dst-bdaddr-t-src" tabindex="-1"><code>void bacpy(bdaddr_t *dst, bdaddr_t *src);</code> <a class="header-anchor" href="#void-bacpy-bdaddr-t-dst-bdaddr-t-src" aria-label="Permalink to &quot;`void bacpy(bdaddr_t *dst, bdaddr_t *src);`&quot;">​</a></h4><p><strong>做什么</strong>：把蓝牙地址从 <code>src</code> 拷贝到 <code>dst</code>。</p><h4 id="int-hci-send-frame-struct-sk-buff-skb" tabindex="-1"><code>int hci_send_frame(struct sk_buff *skb);</code> <a class="header-anchor" href="#int-hci-send-frame-struct-sk-buff-skb" aria-label="Permalink to &quot;`int hci_send_frame(struct sk_buff *skb);`&quot;">​</a></h4><p><strong>做什么</strong>：发送 HCI 层的数据包（命令或数据）。 <strong>地位</strong>：蓝牙传输的「总闸门」。</p><h4 id="int-hci-register-dev-struct-hci-dev-hdev" tabindex="-1"><code>int hci_register_dev(struct hci_dev *hdev);</code> <a class="header-anchor" href="#int-hci-register-dev-struct-hci-dev-hdev" aria-label="Permalink to &quot;`int hci_register_dev(struct hci_dev *hdev);`&quot;">​</a></h4><p><strong>做什么</strong>：向内核注册一个 HCI 设备。 <strong>坑</strong>：如果 <code>hdev</code> 里的 <code>open()</code> 或 <code>close()</code> 回调没定义，直接返回 <code>-EINVAL</code>。它还会设置 <code>HCI_SETUP</code> 标志，并创建对应的 sysfs 条目。</p><h4 id="void-hci-unregister-dev-struct-hci-dev-hdev" tabindex="-1"><code>void hci_unregister_dev(struct hci_dev *hdev);</code> <a class="header-anchor" href="#void-hci-unregister-dev-struct-hci-dev-hdev" aria-label="Permalink to &quot;`void hci_unregister_dev(struct hci_dev *hdev);`&quot;">​</a></h4><p><strong>做什么</strong>：注销 HCI 设备。 <strong>动作</strong>：设置 <code>HCI_UNREGISTER</code> 标志，删掉 sysfs 条目。</p><h4 id="int-hci-event-packet-struct-hci-dev-hdev-struct-sk-buff-skb" tabindex="-1"><code>int hci_event_packet(struct hci_dev *hdev, struct sk_buff *skb);</code> <a class="header-anchor" href="#int-hci-event-packet-struct-hci-dev-hdev-struct-sk-buff-skb" aria-label="Permalink to &quot;`int hci_event_packet(struct hci_dev *hdev, struct sk_buff *skb);`&quot;">​</a></h4><p><strong>做什么</strong>：处理从 HCI 层收上来的事件包。 <strong>触发</strong>：由 <code>hci_rx_work()</code> 调用，是事件处理器的入口。</p><hr><h3 id="_6lowpan" tabindex="-1">6LoWPAN <a class="header-anchor" href="#_6lowpan" aria-label="Permalink to &quot;6LoWPAN&quot;">​</a></h3><p>在低功耗无线网络上跑 IPv6，靠的是这个适配层。</p><h4 id="int-lowpan-rcv-struct-sk-buff-skb-struct-net-device-dev-struct-packet-type-pt-struct-net-device-orig-dev" tabindex="-1"><code>int lowpan_rcv(struct sk_buff *skb, struct net_device *dev, struct packet_type *pt, struct net_device *orig_dev);</code> <a class="header-anchor" href="#int-lowpan-rcv-struct-sk-buff-skb-struct-net-device-dev-struct-packet-type-pt-struct-net-device-orig-dev" aria-label="Permalink to &quot;`int lowpan_rcv(struct sk_buff *skb, struct net_device *dev, struct packet_type *pt, struct net_device *orig_dev);`&quot;">​</a></h4><p><strong>做什么</strong>：6LoWPAN 的主接收处理函数。 <strong>特征</strong>：这种包的以太网类型是 <code>0x00F6</code>。</p><hr><h3 id="pci-子系统" tabindex="-1">PCI 子系统 <a class="header-anchor" href="#pci-子系统" aria-label="Permalink to &quot;PCI 子系统&quot;">​</a></h3><p>绝大多数网卡都是 PCI 设备。这些是驱动与 PCI 总线交互的基础。</p><h4 id="void-pci-unregister-driver-struct-pci-driver-dev" tabindex="-1"><code>void pci_unregister_driver(struct pci_driver *dev);</code> <a class="header-anchor" href="#void-pci-unregister-driver-struct-pci-driver-dev" aria-label="Permalink to &quot;`void pci_unregister_driver(struct pci_driver *dev);`&quot;">​</a></h4><p><strong>做什么</strong>：注销 PCI 驱动。 <strong>位置</strong>：通常写在模块的 <code>exit</code> 函数里。</p><h4 id="int-pci-enable-device-struct-pci-dev-dev" tabindex="-1"><code>int pci_enable_device(struct pci_dev *dev);</code> <a class="header-anchor" href="#int-pci-enable-device-struct-pci-dev-dev" aria-label="Permalink to &quot;`int pci_enable_device(struct pci_dev *dev);`&quot;">​</a></h4><p><strong>做什么</strong>：唤醒并初始化 PCI 设备。 <strong>时机</strong>：在驱动真正开始使用设备前，必须先调这个。</p><h4 id="int-request-irq-unsigned-int-irq-irq-handler-t-handler-unsigned-long-flags-const-char-name-void-dev" tabindex="-1"><code>int request_irq(unsigned int irq, irq_handler_t handler, unsigned long flags, const char *name, void *dev);</code> <a class="header-anchor" href="#int-request-irq-unsigned-int-irq-irq-handler-t-handler-unsigned-long-flags-const-char-name-void-dev" aria-label="Permalink to &quot;`int request_irq(unsigned int irq, irq_handler_t handler, unsigned long flags, const char *name, void *dev);`&quot;">​</a></h4><p><strong>做什么</strong>：注册中断服务程序。 <strong>绑定</strong>：把你的处理函数 <code>handler</code> 挂到中断线 <code>irq</code> 上。</p><h4 id="void-free-irq-unsigned-int-irq-void-dev-id" tabindex="-1"><code>void free_irq(unsigned int irq, void *dev_id);</code> <a class="header-anchor" href="#void-free-irq-unsigned-int-irq-void-dev-id" aria-label="Permalink to &quot;`void free_irq(unsigned int irq, void *dev_id);`&quot;">​</a></h4><p><strong>做什么</strong>：释放中断线。 <strong>对应</strong>：<code>request_irq</code> 的反操作。</p><hr><h3 id="nfc-near-field-communication" tabindex="-1">NFC (Near Field Communication) <a class="header-anchor" href="#nfc-near-field-communication" aria-label="Permalink to &quot;NFC (Near Field Communication)&quot;">​</a></h3><p>NFC 子系统的初始化和设备注册。</p><h4 id="int-nfc-init-void" tabindex="-1"><code>int nfc_init(void);</code> <a class="header-anchor" href="#int-nfc-init-void" aria-label="Permalink to &quot;`int nfc_init(void);`&quot;">​</a></h4><p><strong>做什么</strong>：NFC 子系统的总初始化。 <strong>动作</strong>：注册 Generic Netlink 家族、初始化 Raw Socket、LLCP Socket 和 AF_NFC 协议。</p><h4 id="int-nfc-register-device-struct-nfc-dev-dev" tabindex="-1"><code>int nfc_register_device(struct nfc_dev *dev);</code> <a class="header-anchor" href="#int-nfc-register-device-struct-nfc-dev-dev" aria-label="Permalink to &quot;`int nfc_register_device(struct nfc_dev *dev);`&quot;">​</a></h4><p><strong>做什么</strong>：向 NFC 核心层注册一个 NFC 设备。</p><h4 id="int-nfc-hci-register-device-struct-nfc-hci-dev-hdev" tabindex="-1"><code>int nfc_hci_register_device(struct nfc_hci_dev *hdev);</code> <a class="header-anchor" href="#int-nfc-hci-register-device-struct-nfc-hci-dev-hdev" aria-label="Permalink to &quot;`int nfc_hci_register_device(struct nfc_hci_dev *hdev);`&quot;">​</a></h4><p><strong>做什么</strong>：注册一个 NFC HCI 设备。</p><h4 id="int-nci-register-device-struct-nci-dev-ndev" tabindex="-1"><code>int nci_register_device(struct nci_dev *ndev);</code> <a class="header-anchor" href="#int-nci-register-device-struct-nci-dev-ndev" aria-label="Permalink to &quot;`int nci_register_device(struct nci_dev *ndev);`&quot;">​</a></h4><p><strong>做什么</strong>：注册一个 NFC NCI 设备。</p><hr><h3 id="pppoe-point-to-point-protocol-over-ethernet" tabindex="-1">PPPoE (Point-to-Point Protocol over Ethernet) <a class="header-anchor" href="#pppoe-point-to-point-protocol-over-ethernet" aria-label="Permalink to &quot;PPPoE (Point-to-Point Protocol over Ethernet)&quot;">​</a></h3><p>这是 DSL 连接背后的协议。下面是它的核心操作。</p><h4 id="static-int-init-pppoe-init-void" tabindex="-1"><code>static int __init pppoe_init(void);</code> <a class="header-anchor" href="#static-int-init-pppoe-init-void" aria-label="Permalink to &quot;`static int __init pppoe_init(void);`&quot;">​</a></h4><p><strong>做什么</strong>：PPPoE 层的入口初始化。 <strong>动作</strong>：注册协议处理器、Socket 类型、网络通知链以及 <code>/proc</code> 条目。</p><h4 id="struct-pppoe-hdr-pppoe-hdr-const-struct-sk-buff-skb" tabindex="-1"><code>struct pppoe_hdr *pppoe_hdr(const struct sk_buff *skb);</code> <a class="header-anchor" href="#struct-pppoe-hdr-pppoe-hdr-const-struct-sk-buff-skb" aria-label="Permalink to &quot;`struct pppoe_hdr *pppoe_hdr(const struct sk_buff *skb);`&quot;">​</a></h4><p><strong>做什么</strong>：从一个 Socket 缓冲区里提取 PPPoE 头部。</p><h4 id="static-int-pppoe-create-struct-net-net-struct-socket-sock" tabindex="-1"><code>static int pppoe_create(struct net *net, struct socket *sock);</code> <a class="header-anchor" href="#static-int-pppoe-create-struct-net-net-struct-socket-sock" aria-label="Permalink to &quot;`static int pppoe_create(struct net *net, struct socket *sock);`&quot;">​</a></h4><p><strong>做什么</strong>：创建一个 PPPoE Socket。 <strong>错误</strong>：如果 <code>sk_alloc()</code> 分配失败，返回 <code>-ENOMEM</code>。</p><h4 id="int-set-item-struct-pppoe-net-pn-struct-pppox-sock-po" tabindex="-1"><code>int __set_item(struct pppoe_net *pn, struct pppox_sock *po);</code> <a class="header-anchor" href="#int-set-item-struct-pppoe-net-pn-struct-pppox-sock-po" aria-label="Permalink to &quot;`int __set_item(struct pppoe_net *pn, struct pppox_sock *po);`&quot;">​</a></h4><p><strong>做什么</strong>：把一个 PPPoE Socket 插入哈希表。 <strong>哈希键</strong>：根据 Session ID 和对方 MAC 地址算出来的。</p><h4 id="void-delete-item-struct-pppoe-net-pn-be16-sid-char-addr-int-ifindex" tabindex="-1"><code>void delete_item(struct pppoe_net *pn, __be16 sid, char *addr, int ifindex);</code> <a class="header-anchor" href="#void-delete-item-struct-pppoe-net-pn-be16-sid-char-addr-int-ifindex" aria-label="Permalink to &quot;`void delete_item(struct pppoe_net *pn, __be16 sid, char *addr, int ifindex);`&quot;">​</a></h4><p><strong>做什么</strong>：从哈希表里删掉一个 PPPoE Socket。 <strong>定位</strong>：靠 Session ID、MAC 地址和网卡索引三者共同定位。</p><h4 id="bool-stage-session-be16-sid" tabindex="-1"><code>bool stage_session(__be16 sid);</code> <a class="header-anchor" href="#bool-stage-session-be16-sid" aria-label="Permalink to &quot;`bool stage_session(__be16 sid);`&quot;">​</a></h4><p><strong>做什么</strong>：判断 Session ID 是否有效（非 0）。</p><hr><h3 id="通知链" tabindex="-1">通知链 <a class="header-anchor" href="#通知链" aria-label="Permalink to &quot;通知链&quot;">​</a></h3><p>这是内核里「大喊一声让所有人都听见」的机制。我们在前面看到网络设备状态变化时全靠它。</p><h4 id="int-notifier-chain-register-struct-notifier-block-nl-struct-notifier-block-n" tabindex="-1"><code>int notifier_chain_register(struct notifier_block **nl, struct notifier_block *n);</code> <a class="header-anchor" href="#int-notifier-chain-register-struct-notifier-block-nl-struct-notifier-block-n" aria-label="Permalink to &quot;`int notifier_chain_register(struct notifier_block **nl, struct notifier_block *n);`&quot;">​</a></h4><p><strong>做什么</strong>：把一个回调块 <code>n</code> 挂到链表 <code>nl</code> 上。 <strong>注意</strong>：这是底层原语，实际使用时通常有封装函数。</p><h4 id="int-notifier-chain-unregister-struct-notifier-block-nl-struct-notifier-block-n" tabindex="-1"><code>int notifier_chain_unregister(struct notifier_block **nl, struct notifier_block *n);</code> <a class="header-anchor" href="#int-notifier-chain-unregister-struct-notifier-block-nl-struct-notifier-block-n" aria-label="Permalink to &quot;`int notifier_chain_unregister(struct notifier_block **nl, struct notifier_block *n);`&quot;">​</a></h4><p><strong>做什么</strong>：从链表上摘掉一个回调块。</p><h4 id="int-register-netdevice-notifier-struct-notifier-block-nb" tabindex="-1"><code>int register_netdevice_notifier(struct notifier_block *nb);</code> <a class="header-anchor" href="#int-register-netdevice-notifier-struct-notifier-block-nb" aria-label="Permalink to &quot;`int register_netdevice_notifier(struct notifier_block *nb);`&quot;">​</a></h4><p><strong>做什么</strong>：注册到网络设备通知链（<code>netdev_chain</code>）。 <strong>封装</strong>：里面调的是 <code>raw_notifier_chain_register()</code>。</p><h4 id="int-unregister-netdevice-notifier-struct-notifier-block-nb" tabindex="-1"><code>int unregister_netdevice_notifier(struct notifier_block *nb);</code> <a class="header-anchor" href="#int-unregister-netdevice-notifier-struct-notifier-block-nb" aria-label="Permalink to &quot;`int unregister_netdevice_notifier(struct notifier_block *nb);`&quot;">​</a></h4><p><strong>做什么</strong>：从网络设备通知链注销。</p><h4 id="int-register-inet6addr-notifier-struct-notifier-block-nb" tabindex="-1"><code>int register_inet6addr_notifier(struct notifier_block *nb);</code> <a class="header-anchor" href="#int-register-inet6addr-notifier-struct-notifier-block-nb" aria-label="Permalink to &quot;`int register_inet6addr_notifier(struct notifier_block *nb);`&quot;">​</a></h4><p><strong>做什么</strong>：注册到 IPv6 地址通知链。</p><h4 id="int-unregister-inet6addr-notifier-struct-notifier-block-nb" tabindex="-1"><code>int unregister_inet6addr_notifier(struct notifier_block *nb);</code> <a class="header-anchor" href="#int-unregister-inet6addr-notifier-struct-notifier-block-nb" aria-label="Permalink to &quot;`int unregister_inet6addr_notifier(struct notifier_block *nb);`&quot;">​</a></h4><p><strong>做什么</strong>：从 IPv6 地址通知链注销。</p><h4 id="int-register-netevent-notifier-struct-notifier-block-nb" tabindex="-1"><code>int register_netevent_notifier(struct notifier_block *nb);</code> <a class="header-anchor" href="#int-register-netevent-notifier-struct-notifier-block-nb" aria-label="Permalink to &quot;`int register_netevent_notifier(struct notifier_block *nb);`&quot;">​</a></h4><p><strong>做什么</strong>：注册到网络事件通知链。</p><h4 id="int-unregister-netevent-notifier-struct-notifier-block-nb" tabindex="-1"><code>int unregister_netevent_notifier(struct notifier_block *nb);</code> <a class="header-anchor" href="#int-unregister-netevent-notifier-struct-notifier-block-nb" aria-label="Permalink to &quot;`int unregister_netevent_notifier(struct notifier_block *nb);`&quot;">​</a></h4><p><strong>做什么</strong>：从网络事件通知链注销。</p><h4 id="int-kprobes-notifier-call-chain-struct-notifier-block-nl-unsigned-long-val-void-v-int-nr-to-call-int-nr-calls" tabindex="-1"><code>int __kprobes notifier_call_chain(struct notifier_block **nl, unsigned long val, void *v, int nr_to_call, int nr_calls);</code> <a class="header-anchor" href="#int-kprobes-notifier-call-chain-struct-notifier-block-nl-unsigned-long-val-void-v-int-nr-to-call-int-nr-calls" aria-label="Permalink to &quot;`int __kprobes notifier_call_chain(struct notifier_block **nl, unsigned long val, void *v, int nr_to_call, int nr_calls);`&quot;">​</a></h4><p><strong>做什么</strong>：触发通知链，让上面挂着的所有回调函数跑一遍。 <strong>底层</strong>：这是引擎，通常不直接用。</p><h4 id="int-call-netdevice-notifiers-unsigned-long-val-struct-net-device-dev" tabindex="-1"><code>int call_netdevice_notifiers(unsigned long val, struct net_device *dev);</code> <a class="header-anchor" href="#int-call-netdevice-notifiers-unsigned-long-val-struct-net-device-dev" aria-label="Permalink to &quot;`int call_netdevice_notifiers(unsigned long val, struct net_device *dev);`&quot;">​</a></h4><p><strong>做什么</strong>：专门给网络设备发通知。 <strong>动作</strong>：调用 <code>raw_notifier_call_chain()</code>。</p><h4 id="int-blocking-notifier-call-chain-struct-blocking-notifier-head-nh-unsigned-long-val-void-v" tabindex="-1"><code>int blocking_notifier_call_chain(struct blocking_notifier_head *nh, unsigned long val, void *v);</code> <a class="header-anchor" href="#int-blocking-notifier-call-chain-struct-blocking-notifier-head-nh-unsigned-long-val-void-v" aria-label="Permalink to &quot;`int blocking_notifier_call_chain(struct blocking_notifier_head *nh, unsigned long val, void *v);`&quot;">​</a></h4><p><strong>做什么</strong>：带锁的通知调用。 <strong>场景</strong>：用在可能睡眠的上下文中。</p><h4 id="int-atomic-notifier-call-chain-struct-atomic-notifier-head-nh-unsigned-long-val-void-v-int-nr-to-call-int-nr-calls" tabindex="-1"><code>int __atomic_notifier_call_chain(struct atomic_notifier_head *nh,unsigned long val, void *v, int nr_to_call, int nr_calls);</code> <a class="header-anchor" href="#int-atomic-notifier-call-chain-struct-atomic-notifier-head-nh-unsigned-long-val-void-v-int-nr-to-call-int-nr-calls" aria-label="Permalink to &quot;`int __atomic_notifier_call_chain(struct atomic_notifier_head *nh,unsigned long val, void *v, int nr_to_call, int nr_calls);`&quot;">​</a></h4><p><strong>做什么</strong>：原子上下文的通知调用（不可睡眠）。</p><hr><p><strong>最后，回到那个关于「驾驭复杂性」的问题</strong>：</p><p>看这份列表，你会发现所有的 API 都在围绕几个核心动作：<strong>注册</strong>、<strong>注销</strong>、<strong>关联</strong>、<strong>查找</strong>。内核网络子系统再庞大，本质上也就是这些动作在无数的层级和对象之间反复上演。</p><p>当你真的理解了这一章里的这些工具——知道它们什么时候被调用，为什么要这样设计——你就不再是单纯地在「用」Linux 网络了，你是在「懂」它。</p><p>祝你的下一次调试不再迷茫。</p>',176)])])}const g=e(s,[["render",i]]);export{h as __pageData,g as default};
